{
  "title": "परिवर्तनीय संदर्भ",
  "group": "उधारी",
  "options": [
    {
      "text": "सफलतापूर्वक संकलित होता है",
      "hint": "क्या हम एक ही समय में कई परिवर्तनीय संदर्भ रख सकते हैं?"
    },
    {
      "text": "त्रुटि: `wisdom` को एक से अधिक बार परिवर्तनीय रूप में उधार नहीं ले सकते"
    },
    {
      "text": "त्रुटि: लाइफ़टाइम निर्दिष्टकर्ता गायब है",
      "hint": "यहाँ समस्या लाइफ़टाइम्स की नहीं है"
    },
    {
      "text": "रनटाइम पैनिक",
      "hint": "रस्ट इन समस्याओं को संकलन समय पर पकड़ लेता है"
    }
  ],
  "questionProse": [
    "कई परिवर्तनीय संदर्भों से क्या होता है?",
    "रस्ट के परिवर्तनीय संदर्भों के नियमों के बारे में सोचें।"
  ],
  "explanationProse": [
    "यह कोड रस्ट के मूल उधारी नियमों का उल्लंघन करता है:\n      - एक समय में केवल ONE परिवर्तनीय संदर्भ\n      - या किसी भी संख्या में अपरिवर्तनीय संदर्भ\n      - संदर्भ अपने स्रोत से अधिक समय तक नहीं रह सकते\n\n      कोड को ठीक करने का तरीका:\n\n      1. क्रमिक स्कोपिंग का उपयोग करें:",
    "2. या एक ही उधार में स्ट्रिंग को संशोधित करें:",
    "ये नियम संकलन समय पर डेटा रेस को रोकते हैं, जिससे रस्ट डिफ़ॉल्ट रूप से थ्रेड‑सेफ़ बनता है।\n\n      सामान्य गलती: कई परिवर्तनीय संदर्भों का उपयोग करके क्लोनिंग से बचने या\n      एक ही मान के विभिन्न भागों को एक साथ संशोधित करने की कोशिश करना।"
  ]
}
